def num_decodings(s):
    n = len(s)

    def helper(i):
        if i == n:
            return 1
        if s[i] == '0':
            return 0
        count = helper(i + 1)
        if i + 1 < n and 10 <= int(s[i:i + 2]) <= 26:
            count += helper(i + 2)
        return count

    return helper(0) if n else 0

def num_decodings(s):
    n = len(s)
    if n == 0:
        return 0
    prev2 = 1
    prev1 = 1 if s[0] != '0' else 0
    for i in range(1, n):
        cur = 0
        if s[i] != '0':
            cur += prev1
        two = int(s[i - 1:i + 1])
        if 10 <= two <= 26:
            cur += prev2
        prev2, prev1 = prev1, cur
    return prev1
